import React, { useState } from 'react';
import './inserirAtendimento.css';

const InserirAtendimento = () => {
    const [dataAtendimento, setDataAtendimento] = useState('');
    const [assunto, setAssunto] = useState('');
    const [situacao, setSituacao] = useState('Ativo');
    const [descricao, setDescricao] = useState('');
    const [pessoa, setPessoa] = useState('');

    const handleSubmit = (event) => {
        event.preventDefault();
        // Aqui você pode adicionar a lógica para salvar os dados do atendimento
        console.log({ dataAtendimento, assunto, situacao, descricao, pessoa });
    };

    return (
        <div className="container">
            <h1>Inserir atendimento</h1>
            <form onSubmit={handleSubmit}>
                <div className="section">
                    <h2>Dados Básicos</h2>
                    <div className="input-group">
                        <label>Data de atendimento:</label>
                        <input 
                            type="date" 
                            value={dataAtendimento} 
                            onChange={(e) => setDataAtendimento(e.target.value)} 
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Assunto:</label>
                        <input 
                            type="text" 
                            value={assunto} 
                            onChange={(e) => setAssunto(e.target.value)} 
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Situação:</label>
                        <select 
                            value={situacao} 
                            onChange={(e) => setSituacao(e.target.value)}>
                            <option value="Ativo">Ativo</option>
                            <option value="Inativo">Inativo</option>
                        </select>
                    </div>
                    <div className="input-group">
                        <label>Descrição:</label>
                        <textarea 
                            value={descricao} 
                            onChange={(e) => setDescricao(e.target.value)} 
                            rows="4"
                        ></textarea>
                    </div>
                </div>

                <div className="section">
                    <h2>Envolvidos</h2>
                    <div className="input-group">
                        <label>Pessoa:</label>
                        <input 
                            type="text" 
                            placeholder="Buscar uma pessoa já cadastrada" 
                            value={pessoa} 
                            onChange={(e) => setPessoa(e.target.value)}
                        />
                    </div>
                </div>

                <div className="button-group">
                    <button type="submit" className="btn">Salvar</button>
                    <button type="button" className="btn cancel">Cancelar</button>
                </div>
            </form>
        </div>
    );
};

export default InserirAtendimento;
